def find_service_by_name(name_fragment: str, token: str) -> list[dict]:
    """Search Azure Support services by display name fragment."""
    url = (
        "https://management.azure.com/providers/Microsoft.Support/services"
        "?api-version=2020-04-01"
    )
    resp = requests.get(url, headers={"Authorization": f"Bearer {token}"}, timeout=30)
    resp.raise_for_status()
    services = resp.json().get("value", [])
    return [
        {"id": s["name"], "display_name": s["properties"]["displayName"]}
        for s in services
        if name_fragment.lower() in s["properties"]["displayName"].lower()
    ]

